<?php
 namespace WPAICG\Core\Stream\Cache; if (!defined('ABSPATH')) { exit; } function delete_logic(\WPAICG\Core\Stream\Cache\AIPKit_SSE_Message_Cache $cacheInstance, string $key): bool { if (empty($key)) { return false; } $deleted_from_db = false; $deleted_from_object_cache = false; global $wpdb; $deleted_db = $wpdb->delete( $cacheInstance->get_db_table_name(), ['cache_key' => $key], ['%s'] ); if ($deleted_db !== false) { $deleted_from_db = true; } if ($cacheInstance->is_using_object_cache()) { $deleted_from_object_cache = wp_cache_delete($key, $cacheInstance::CACHE_GROUP); } return $deleted_from_db || $deleted_from_object_cache; } 